<?php
namespace App\Modules\Drivers\Presentation;
use App\Http\Controllers\Controller; use App\Models\Driver; use App\Models\Trip; use App\Modules\Drivers\Application\Services\DriverShiftService; use App\Modules\Drivers\Application\Services\DriverTripService; use App\Modules\Drivers\Application\Services\TripTimelineService; use App\Modules\Gps\Application\GpsService; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request;
final class DriverController extends Controller { public function __construct(private readonly DriverShiftService $shifts, private readonly DriverTripService $trips, private readonly TripTimelineService $timeline, private readonly GpsService $gps) {} private function driver(Request $request): Driver { return Driver::query()->where('user_id',$request->user()?->id)->firstOrFail(); } public function dashboard(Request $r): JsonResponse { $d=$this->driver($r); return response()->json(['data'=>['shift'=>$this->shifts->currentShift($d),'today_trips'=>Trip::where('driver_id',$d->id)->whereDate('created_at',today())->count(),'earnings_today'=>(float)Trip::where('driver_id',$d->id)->whereDate('created_at',today())->sum('earnings_amount'),'active_trip'=>Trip::where('driver_id',$d->id)->whereNotIn('status',['completed','cancelled','failed'])->latest()->first(),'assigned_trips'=>Trip::where('driver_id',$d->id)->whereIn('status',['ready','assigned'])->with(['schedule.route'])->latest()->get()]]); } public function trips(Request $r): JsonResponse { $d=$this->driver($r); return response()->json(['data'=>Trip::where('driver_id',$d->id)->whereDate('created_at',today())->latest()->get()]); } public function history(Request $r): JsonResponse { $d=$this->driver($r); return response()->json(['data'=>Trip::where('driver_id',$d->id)->whereIn('status',['completed','cancelled','failed'])->latest()->paginate(20)]); } public function earnings(Request $r): JsonResponse { $d=$this->driver($r); $q=Trip::where('driver_id',$d->id); $done=(clone $q)->where('status','completed')->count(); $total=(clone $q)->count(); return response()->json(['data'=>['total_trip'=>$total,'total_kilometer'=>(float)(clone $q)->sum('distance_km'),'jam_kerja'=>0,'trip_hari_ini'=>(clone $q)->whereDate('created_at',today())->count(),'pendapatan_hari_ini'=>(float)(clone $q)->whereDate('created_at',today())->sum('earnings_amount'),'pendapatan_bulan_ini'=>(float)(clone $q)->whereMonth('created_at',now()->month)->sum('earnings_amount'),'completion_rate'=>$total?round($done/$total*100,2):0,'rating'=>(float)($d->metadata['rating']??0),'no_show'=>(int)($d->metadata['no_show']??0),'cancellation_rate'=>$total?round((clone $q)->where('status','cancelled')->count()/$total*100,2):0]]); } public function timeline(Request $r): JsonResponse { return response()->json(['data'=>$this->timeline->forDriver($this->driver($r)->id)]); } public function startShift(Request $r): JsonResponse { return response()->json(['data'=>$this->shifts->startShift($this->driver($r))]); } public function endShift(Request $r): JsonResponse { return response()->json(['data'=>$this->shifts->endShift($this->driver($r))]); } public function break(Request $r): JsonResponse { return response()->json(['data'=>$this->shifts->breakShift($this->driver($r))]); } public function resume(Request $r): JsonResponse { return response()->json(['data'=>$this->shifts->resumeShift($this->driver($r))]); } public function startTrip(Request $r): JsonResponse { $trip=$this->ownedTrip($r); $driver=\App\Models\Driver::where('user_id',$r->user()?->id)->first(); abort_unless(in_array($driver?->status,['available','on_duty','on_trip'],true),422,'Mulai shift terlebih dahulu sebelum memulai trip. Buka menu Shift lalu tekan Mulai Shift.'); $result=$this->trips->advanceTo($trip,\App\Modules\Drivers\Application\StateMachines\DriverTripStateMachine::STARTED); \App\Models\ActivityLog::create(['action'=>'trip.started','subject_type'=>'Trip','subject_id'=>$trip->id,'metadata'=>\App\Support\Audit\RequestContext::enrich($r,['trip_id'=>$trip->id])]); app(\App\Modules\Drivers\Application\Services\TripNotificationService::class)->notifyTrip($trip->fresh(),'Perjalanan dimulai','Driver telah memulai perjalanan Anda. Pantau posisi driver melalui tombol Track Driver di halaman booking.'); return response()->json(['data'=>$result]); } public function finishTrip(Request $r): JsonResponse { $trip=$this->ownedTrip($r); $result=$this->trips->advanceTo($trip,\App\Modules\Drivers\Application\StateMachines\DriverTripStateMachine::COMPLETED); \App\Models\ActivityLog::create(['action'=>'trip.finished','subject_type'=>'Trip','subject_id'=>$trip->id,'metadata'=>\App\Support\Audit\RequestContext::enrich($r,['trip_id'=>$trip->id])]); app(\App\Modules\Drivers\Application\Services\TripNotificationService::class)->notifyTrip($trip->fresh(),'Trip selesai','Perjalanan Anda telah selesai. Terima kasih telah menggunakan layanan kami!'); return response()->json(['data'=>$result]); } /** Guard against IDOR: the trip must belong to the authenticated driver. */ private function ownedTrip(Request $r): Trip { $trip=Trip::findOrFail($r->integer('trip_id')); abort_unless($trip->driver_id === $this->driver($r)->id, 403, 'Trip ini bukan milik Anda.'); return $trip; } public function location(Request $r): JsonResponse { $d=$this->driver($r); $data=$r->validate(['trip_id'=>'required|integer','latitude'=>'required|numeric|between:-90,90','longitude'=>'required|numeric|between:-180,180','speed'=>'nullable|numeric','heading'=>'nullable|numeric','accuracy'=>'nullable|numeric','battery'=>'nullable|integer|between:0,100']); abort_unless(Trip::where('id',(int)$data['trip_id'])->where('driver_id',$d->id)->exists(), 403, 'Trip ini bukan milik Anda.'); $this->gps->updateLocation((string)$d->id,(string)$data['trip_id'],(float)$data['latitude'],(float)$data['longitude'],$data['speed']??null,$data['heading']??null,$data['accuracy']??null,$data['battery']??null); return response()->json(['data'=>$this->gps->heartbeat((string)$d->id,(string)$data['trip_id'])]); }}
